  0x02, 0x01, 0x00, 0x0a, 0x0a, 0x01, 0x08, 0x00,
  0x41, 0x00, 0xfd, 0x0f, 0x26, 0x0b
]));
console.log('SIMD supported:', simdSupported);
```

