Verifying SIMD is Active

Check the console output when initializing. You should see:
```
[RuvectorStore] ONNX fast embeddings loaded successfully (~55x faster)
PersistentVectorDB initialized: .ruvector/knowledge-base (17000 vectors)
```

If ONNX fails, you will see a warning and it falls back to ruvector native or @xenova/transformers.

Complete setup guide for a private RAG system using RuVector, local ONNX embeddings, and Ollama as the LLM backend.

Step 1: Install RuVector and Dependencies

```bash
# Core RuVector package
npm install ruvector

# ONNX embedding runtime (local, no API calls)
npm install @claude-flow/embeddings
# or: npm install @xenova/transformers

# Install Ollama (local LLM runtime)
curl -fsSL https://ollama.ai/install.sh | sh

# Pull a model (runs entirely locally after this)
ollama pull llama3.2:3b       # 2.0 GB, fast on CPU
ollama pull phi3:mini          # 2.3 GB, excellent quality/size
ollama pull mistral:7b         # 4.1 GB, strong reasoning
ollama pull llama3.1:8b        # 4.9 GB, best quality at 8B
```

Step 2: Initialize the Vector Store

```javascript
// setup-rag.js
const { getPersistentVectorDB } = require('./src/storage/persistent-vector-db');

async function initVectorDB() {
  const db = await getPersistentVectorDB('my-docs', {
    dimensions: 384,           // all-MiniLM-L6-v2 output size
    distanceMetric: 'Cosine',
    saveIntervalMs: 2000,
    useWAL: true
  });

  console.log('Vector DB ready:', db.getStats());
  return db;
}
```

Step 3: Ingest Documents Privately

```javascript
// ingest.js
const fs = require('fs');
const path = require('path');

// Load local ONNX embedding model (downloads once to ~/.cache)
async function getEmbedder() {
  const { createEmbeddingServiceAsync } = await import(
    '@claude-flow/embeddings'
  );
  return createEmbeddingServiceAsync({
    provider: 'transformers',
    model: 'Xenova/all-MiniLM-L6-v2',
    dimensions: 384
  });
}

function chunkText(text, chunkSize = 2000, overlap = 200) {
  const chunks = [];
  let start = 0;
  while (start < text.length) {
    chunks.push(text.slice(start, start + chunkSize));
    start += chunkSize - overlap;
  }
  return chunks;
}

async function ingestDocument(db, embedder, filePath) {
  const text = fs.readFileSync(filePath, 'utf8');
  const chunks = chunkText(text);

  console.log(`Ingesting ${path.basename(filePath)}: ${chunks.length} chunks`);

  for (let i = 0; i < chunks.length; i++) {
    const embedding = await embedder.embed(chunks[i]);
    await db.insert({
      id: `${path.basename(filePath)}-chunk-${i}`,
      vector: new Float32Array(embedding),
      metadata: {
        content: chunks[i],
        source: filePath,
        chunkIndex: i
      }
    });
  }

  await db.flush(); // Persist to disk
  console.log('Ingestion complete. All data stays local.');
}
```

Step 4: Query Pipeline (Fully Local)

```javascript
// query.js
const { default: ollama } = require('ollama');

async function ragQuery(db, embedder, question) {
  // 1. Embed the question locally (no API call)
  const queryVector = await embedder.embed(question);

  // 2. Search vector DB (local HNSW, 61 microsecond latency)
  const results = await db.search({
    vector: new Float32Array(queryVector),
    k: 5
  });

  // 3. Build context from retrieved chunks
  const context = results
    .map(r => r.metadata.content)
    .join('\n\n---\n\n');

  // 4. Call local LLM (Ollama, no internet after model download)
  const response = await ollama.chat({
    model: 'llama3.2:3b',
    messages: [
      {
        role: 'system',
        content: 'Answer based on the provided context. If not in context, say so.'
      },
      {
        role: 'user',
        content: `Context:\n${context}\n\nQuestion: ${question}`
      }
    ],
    stream: true  // Stream tokens as they generate
  });

  // 5. Stream output
  for await (const chunk of response) {
    process.stdout.write(chunk.message.content);
  }
}
```

Step 5: Verify Zero External Calls

```bash
# Monitor network while running your RAG
sudo lsof -i -n | grep node
# Should show ONLY local connections (127.0.0.1)

# Or use network monitoring
nmap --script=discovery localhost
```

Full Pipeline Test

```bash
# Run the complete private RAG
node -e "
  const db = await initVectorDB();
  const embedder = await getEmbedder();
  await ingestDocument(db, embedder, './my-document.pdf');
  await ragQuery(db, embedder, 'What is the main topic?');
"
```

Document ingestion is the first phase of any RAG system. Getting it right determines retrieval quality. This covers ingestion patterns used in the Ask-Ruvnet codebase and best practices for private deployment.

Chunking Strategy

The Ask-Ruvnet project uses TextChunker with these defaults:
- Chunk size: 2000 characters
- Overlap: 200 characters (10% overlap prevents context loss at boundaries)

Chunking patterns by document type:

For prose documents (articles, reports):
```javascript
// Paragraph-aware chunking
const chunks = text.split(/\n\n+/).filter(p => p.trim().length > 100);
// Then merge short paragraphs until chunk hits target size
```

For code documentation:
```javascript
// Section-based chunking (keep code blocks intact)
const sections = text.split(/^#{1,3}\s/m);
// Never split inside a code fence
```

For structured data (PDFs with tables):
```javascript
// Use SciPix (RuVector's OCR component) for LaTeX/MathML extraction
// npm install @ruvector/scipix
const scipix = require('@ruvector/scipix');
const extracted = await scipix.extractPDF(buffer);
```

Batch Ingestion Pattern (from this codebase)

```javascript
// RuvectorStore.addDocumentsBatch - the actual production implementation
async function addDocumentsBatch(documents) {
  const contents = documents.map(doc => doc.content || '');

  // ONNX batch embedding: much faster than one-by-one
  let batchEmbeddings = null;
  try {
    const svc = await getOnnxService();
    if (svc && svc.embedBatch && contents.length > 1) {
      const batchResult = await svc.embedBatch(contents);
      batchEmbeddings = batchResult.embeddings.map(e => e.embedding);
    }
  } catch (err) {
    // Falls back to individual embedding
  }

  for (let i = 0; i < documents.length; i++) {
    const embedding = batchEmbeddings
      ? batchEmbeddings[i]
      : await generateEmbedding(contents[i]);

    await db.insert({
      id: doc.id || `doc_${Date.now()}_${i}`,
      vector: embedding,
      metadata: {
        content: contents[i],
        name: doc.name,
        source: doc.metadata?.source,
        timestamp: new Date().toISOString()
      }
    });
  }
}
```

Supported Document Types

The codebase handles these formats for private ingestion:
- Plain text (.txt, .md): Direct read
- PDF: pdf-parse library (local, no API)
- Word documents: mammoth library (local conversion to text)
- Images with text: tesseract.js (local OCR)
- Videos: fluent-ffmpeg (frame extraction) + tesseract for OCR

Deduplication Before Ingestion

To avoid storing duplicate content:

```javascript
// Jaccard similarity check before insert (from app.js diversity filter)
function calculateJaccardSimilarity(str1, str2) {
  const words1 = new Set(str1.split(/\s+/).filter(w => w.length > 3));
  const words2 = new Set(str2.split(/\s+/).filter(w => w.length > 3));
  if (words1.size === 0 || words2.size === 0) return 0;
  const intersection = [...words1].filter(w => words2.has(w)).length;
  const union = new Set([...words1, ...words2]).size;
  return intersection / union;
}
// Skip insert if similarity > 0.7 with existing chunks
```

Metadata Enrichment

Store rich metadata alongside vectors for filtered retrieval:

```javascript
await db.insert({
  id: docId,
  vector: embedding,
  metadata: {
    content: chunkText,
    source: filePath,
    docTitle: document.title,
    author: document.author,
    createdAt: document.date,
    chunkIndex: i,
    totalChunks: chunks.length,
    classification: 'confidential',  // For access control
    department: 'legal'
  }
});
```

Recency Boost (from RuvectorStore)

The Ask-Ruvnet codebase applies recency boost during retrieval, not ingestion. Newer documents score slightly higher:

```javascript
// applyRecencyBoost from RecencyBoost.js
function applyRecencyBoost(results) {
  const now = Date.now();
  return results.map(r => {
    const age = now - new Date(r.metadata.timestamp).getTime();
    const ageDays = age / (1000 * 60 * 60 * 24);
    const boost = Math.exp(-ageDays / 30); // Decay over 30 days
    return { ...r, score: r.score * (1 + 0.1 * boost) };
  }).sort((a, b) => b.score - a.score);
}
```

Persistence Verification

After ingestion, verify data survived:

```javascript
const stats = db.getStats();
console.log('Vectors stored:', stats.vectorCount);
console.log('Storage path:', stats.path);

// Verify binary files exist
const files = fs.readdirSync(stats.path);
console.log('Persisted files:', files);
// Expected: vectors.bin, metadata.json, manifest.json
```

Getting acceptable performance from local LLMs requires understanding the hardware, model, and context size trade-offs. This covers real numbers and actionable optimizations.

Token Generation Speed by Hardware

Measurements for Llama 3.1 8B Q4_K_M:

Apple Silicon (Metal GPU acceleration via Ollama):
- M1 (8 GPU cores): 15-25 tokens/sec
- M2 (10 GPU cores): 20-35 tokens/sec
- M3 Max (40 GPU cores): 40-80 tokens/sec
- M4 Max (40 GPU cores): 50-95 tokens/sec

NVIDIA GPU:
- RTX 3060 (12GB VRAM): 30-50 tokens/sec
- RTX 4080 (16GB VRAM): 60-100 tokens/sec
- RTX 4090 (24GB VRAM): 80-140 tokens/sec

CPU only:
- Apple M3 Max (CPU only, no Metal): 8-18 tokens/sec
- Intel Core i7-13700H: 3-7 tokens/sec
- AMD Ryzen 9 7900X: 4-8 tokens/sec

For smaller models (Phi-3-mini 3.8B Q4):
- M3 Max (Metal): 80-130 tokens/sec
- M3 Max (CPU): 15-30 tokens/sec
- Intel i7 (CPU): 8-15 tokens/sec

Context Window and Memory Impact

The context window size directly determines RAM usage. For Llama 3.1 8B:
- 4K context: ~5.2 GB RAM
- 8K context: ~5.8 GB RAM
- 16K context: ~7.1 GB RAM
- 32K context: ~9.5 GB RAM
- 128K context: ~25 GB RAM

For RAG workloads, context = retrieved chunks + system prompt + question. Calculate your needed context size:

```javascript
// Context size calculator for RAG
function estimateContextTokens(chunks, systemPrompt, question) {
  const allText = systemPrompt + chunks.join('\n\n') + question;
  // Rough approximation: 1 token ~ 4 characters for English
  return Math.ceil(allText.length / 4);
}

// Example: 5 chunks of 2000 chars + 500 char system prompt + 200 char question
// = (5*2000 + 500 + 200) / 4 = ~2675 tokens
// Well within 4K context, use smaller context window to save RAM
```

Ollama Context Configuration

```javascript
// Set context window via Ollama API
const response = await ollama.chat({
  model: 'llama3.1:8b',
  options: {
    num_ctx: 8192,    // Context window size (balance RAM vs quality)
    num_predict: 512, // Max tokens to generate
    temperature: 0.3, // Lower = more deterministic (better for RAG)
    top_p: 0.9,
    repeat_penalty: 1.1
  },
  messages: [...]
});
```

Batching for Throughput

Ollama processes one request at a time by default. For batch document processing (e.g., nightly summarization of 1000 documents), sequence requests but pre-compute all embeddings in parallel:

```javascript
async function batchProcess(documents, db, embedder) {
  console.log('Phase 1: Batch embedding (parallel, ONNX)');
  const texts = documents.map(d => d.content);
  const embeddings = await embedder.embedBatch(texts); // ~930/sec

  console.log('Phase 2: Store in vector DB');
  for (let i = 0; i < documents.length; i++) {
    await db.insert({ id: `doc-${i}`, vector: embeddings[i], metadata: {...} });
  }

  console.log('Phase 3: Sequential LLM summarization (bottleneck)');
  const summaries = [];
  for (const doc of documents) {
    // Process one at a time (Ollama limitation)
    const summary = await ollama.chat({
      model: 'phi3:mini', // Use fast model for batch
      options: { num_ctx: 4096, num_predict: 256 },
      messages: [{ role: 'user', content: `Summarize: ${doc.content}` }]
    });
    summaries.push(summary.message.content);
  }
  return summaries;
}
```

Memory Management for Large Models

```bash
# Configure Ollama to keep model in memory between requests
# (default: model unloads after 5 minutes of inactivity)
export OLLAMA_KEEP_ALIVE=60m

# Limit model memory usage (if running alongside other services)
export OLLAMA_MAX_LOADED_MODELS=1
export OLLAMA_NUM_PARALLEL=1  # One request at a time

# For Apple Silicon: ensure full GPU offload
# Ollama automatically uses Metal when model fits in VRAM
# Check with:
ollama ps
# Look for '100% GPU' in the output
```

KV Cache Optimization

The KV cache stores computed attention states for reused prefixes (like your system prompt). If your system prompt is identical across requests, the KV cache dramatically speeds up time-to-first-token:

```javascript
// Design your prompts for KV cache reuse
const STATIC_SYSTEM_PROMPT = `You are a private AI assistant for Acme Corp.
Answer based only on provided context. Cite sources.
Never reveal internal document classifications.`;
// ^ This prefix is cached after the first request

// Dynamic part comes after
const messages = [
  { role: 'system', content: STATIC_SYSTEM_PROMPT },  // cached
  { role: 'user', content: `Context:\n${context}\nQuestion: ${question}` } // not cached
];
```

Flash Attention Impact on Local Models

Ollama 0.3+ with llama.cpp enables Flash Attention automatically when supported:

```bash
# Check if Flash Attention is active
OLLAMA_FLASH_ATTENTION=1 ollama serve

# Effect on 8B model with 8K context:
# Without Flash Attention: 580ms time-to-first-token
# With Flash Attention: 320ms time-to-first-token (~1.8x speedup)
```

The 2.49x-7.47x Flash Attention speedup in Ruflo V3 applies to the vector attention mechanisms in the agent orchestration layer (multi-head attention for agent coordination), not to the Ollama LLM inference itself.

The Ask-Ruvnet project implements a multi-stage retrieval pipeline that significantly improves over naive vector search. Understanding each stage helps you build higher-quality private RAG systems.

The Four-Stage RAG Enhancement Pipeline

This is the actual pipeline used in src/server/app.js:

```javascript
// Stage 1: Query Expansion
const queryExpander = new QueryExpander();
// Expands 'database performance' -> ['database performance', 'query optimization', 'index tuning', 'DB throughput']

// Stage 2: Hybrid Search (vector + keyword)
const hybridSearch = new HybridSearch();
// Runs semantic vector search AND BM25 keyword search, merges results

// Stage 3: Reranking
const reRanker = new ReRanker({
  semanticWeight: 0.35,    // How well the chunk matches semantically
  keywordWeight: 0.25,     // Keyword overlap with query
  alignmentWeight: 0.20,   // How directly the chunk answers the question
  recencyWeight: 0.10,     // Newer content ranked slightly higher
  diversityWeight: 0.10    // Avoid redundant chunks from same source
});

// Stage 4: Context Compression
const contextCompressor = new ContextCompressor({
  maxContextLength: 16000,  // Total context limit for the LLM
  maxPerSource: 4000,       // Per-source limit (prevents one doc dominating)
  preserveCode: true        // Never truncate code blocks
});
```

Query Expansion in Detail

Query expansion reduces vocabulary mismatch between user queries and document language. Without it:
- User asks: "how do I speed up my database"
- Document says: "index optimization improves query throughput"
- Vector similarity: medium (related but different vocabulary)

With expansion:
- Expanded queries include: "database performance", "query optimization", "index tuning"
- Multiple searches run in parallel
- Results merged with deduplication

```javascript
// QueryExpander implementation pattern
class QueryExpander {
  expand(query) {
    // 1. Extract key concepts (noun phrases)
    // 2. Add synonyms from domain vocabulary
    // 3. Generate sub-questions for multi-hop retrieval
    return [
      query,                    // Original
      this.extractConcepts(query),  // Concept-focused
      this.addSynonyms(query),      // Synonym variants
    ];
  }
}
```

Hybrid Search: Vector + BM25

Pure vector search misses exact keyword matches (acronyms, proper nouns, version numbers). BM25 captures these:

- "ruvector v2.0.0-alpha.118" - BM25 finds exact version string
- "what is HNSW" - Vector search finds conceptually related content

Combining both with RRF (Reciprocal Rank Fusion):

```javascript
function reciprocalRankFusion(vectorResults, bm25Results, k = 60) {
  const scores = new Map();

  vectorResults.forEach((r, rank) => {
    const prev = scores.get(r.id) || 0;
    scores.set(r.id, prev + 1 / (k + rank + 1));
  });

  bm25Results.forEach((r, rank) => {
    const prev = scores.get(r.id) || 0;
    scores.set(r.id, prev + 1 / (k + rank + 1));
  });

  return [...scores.entries()]
    .sort((a, b) => b[1] - a[1])
    .map(([id, score]) => ({ id, score }));
}
```

Multi-Hop Retrieval

The MultiHopRetriever in this codebase handles questions that require connecting information from multiple documents:

```javascript
const multiHopRetriever = new MultiHopRetriever({
  maxHops: 2,           // Follow up to 2 additional retrieval steps
  minConfidence: 0.3    // Stop if retrieved content confidence drops below 0.3
});
```

Example multi-hop chain:
- Q: "What model does Ask-Ruvnet use for embeddings and how fast is it?"
- Hop 1: Finds chunk about "ONNX embedding model all-MiniLM-L6-v2"
- Hop 2: From that chunk, identifies "@claude-flow/embeddings", retrieves performance data
- Result: Combined answer with both model name and throughput figures

Diversity Filter (Anti-Redundancy)

```javascript
// From app.js: prevents 6 chunks from same document dominating context
function applyDiversityFilter(sources, maxSources = 6) {
  const diverse = [];

  for (const source of sources) {
    const contentFingerprint = source.content.substring(0, 200).toLowerCase();

    let isDuplicate = false;
    for (const existing of diverse) {
      const existingFP = existing.content.substring(0, 200).toLowerCase();
      if (calculateJaccardSimilarity(contentFingerprint, existingFP) > 0.7) {
        isDuplicate = true;
        break;
      }
    }

    if (!isDuplicate) diverse.push(source);
    if (diverse.length >= maxSources) break;
  }

  return diverse;
}
```

Context Compression for LLM Input

Large retrieved context degrades LLM quality ("lost in the middle" problem). Context compression:
1. Extracts most relevant sentences from each chunk
2. Removes redundant phrases
3. Preserves code blocks intact
4. Stays within the 16,000 character limit

Full Pipeline Performance

Measured on the Ask-Ruvnet production system:
- Embedding query: 1-3ms (ONNX local)
- HNSW search (17K vectors): 0.061ms p50
- Query expansion + multi-search: 5-15ms total
- Reranking: 1-2ms
- Context compression: 0.5-1ms
- Total retrieval pipeline: 10-25ms
- LLM generation: 2-30 seconds (depends on model and length)

The retrieval pipeline is not the bottleneck. The LLM is.

Enterprise WASM deployment patterns for healthcare, finance, legal, and government sectors where data cannot leave controlled environments.

Pattern 1: Browser-Native Private AI (Maximum Privacy)

Data never leaves the user's device. Suitable for: patient self-service portals, personal financial planning, legal self-help tools.

```javascript
// Complete browser-side private AI
// patient-portal.html

const RVECTOR_WASM_URL = '/assets/ruvector-wasm.js';  // Hosted on your server
const MODEL_URL = '/assets/phi3-mini-q4.gguf';        // Hosted on your server

async function initPrivateAI() {
  // 1. Load vector DB WASM (5.5 KB)
  const { init, VectorDB } = await import(RVECTOR_WASM_URL);
  await init();
  const vectorDB = new VectorDB({ dimensions: 384 });

  // 2. Load knowledge base into browser (IndexedDB for persistence)
  const cachedKB = await getFromIndexedDB('medical-kb');
  if (cachedKB) {
    await vectorDB.loadFromBuffer(cachedKB);
  } else {
    const response = await fetch('/assets/medical-kb.rvf');
    const rvfData = await response.arrayBuffer();
    await vectorDB.loadRVF(rvfData);
    await saveToIndexedDB('medical-kb', rvfData);
  }

  // 3. Load LLM (cached in IndexedDB after first download)
  const { Wllama } = await import('/assets/wllama.js');
  const wllama = new Wllama('/assets/wllama-worker.js');
  await wllama.loadModelFromUrl(MODEL_URL, {
    n_ctx: 4096,
    // Use SIMD WASM backend automatically
  });

  console.log('Private AI ready. Zero server calls for queries.');
  return { vectorDB, wllama };
}

async function privateQuery(ai, question) {
  // Embed question in browser (WASM SIMD)
  const queryVector = await ai.vectorDB.embedLocally(question);

  // Search browser vector DB (HNSW, <1ms)
  const results = await ai.vectorDB.search({ vector: queryVector, k: 5 });

  // Build context and query local LLM
  const context = results.map(r => r.metadata.content).join('\n\n');
  const answer = await ai.wllama.createCompletion(
    `Context:\n${context}\n\nQuestion: ${question}\n\nAnswer:`
  );

  return answer;
  // ZERO network calls made during this function
}
```

Pattern 2: Dedicated AI Appliance (Air-Gapped Server)

For clinical environments where no internet connectivity is acceptable.

```bash
# Provision appliance (runs in hospital DMZ, no internet)
cat /etc/ai-appliance/setup.sh << 'EOF'
#!/bin/bash
# Runs during initial provisioning (internet allowed once)

# Download everything needed
ollama pull llama3.1:8b
ollama pull phi3:mini
npm pack  # Vendor all node_modules
docker pull ruvnet/ruvector-postgres:latest
docker save ruvnet/ruvector-postgres:latest > /opt/images/ruvector-postgres.tar

# Configure for offline operation
cat >> /etc/environment << 'ENVEOF'
TRANSFORMERS_OFFLINE=1
HF_DATASETS_OFFLINE=1
OLLAMA_ORIGINS=http://localhost:3000
ENVEOF

# Block all external traffic after setup
iptables -I OUTPUT -d 0.0.0.0/0 -j REJECT
iptables -I OUTPUT -d 127.0.0.0/8 -j ACCEPT
iptables -I OUTPUT -d 10.0.0.0/8 -j ACCEPT
iptables -I OUTPUT -d 172.16.0.0/12 -j ACCEPT

echo "Appliance hardened. No internet access."
EOF
```

Pattern 3: Multi-Tenant Private AI (Department Isolation)

Different departments share hardware but have isolated data.

```javascript
// Namespace-based isolation using RuVector collections
const dbByDepartment = {};

async function getDepartmentDB(department) {
  if (dbByDepartment[department]) return dbByDepartment[department];

  const db = await getPersistentVectorDB(`dept-${department}`, {
    dimensions: 384,
    distanceMetric: 'Cosine',
    // Separate file path per department
    path: `.ruvector/departments/${department}`
  });

  dbByDepartment[department] = db;
  return db;
}

// Query isolation: each department only searches its own vectors
async function isolatedQuery(userId, department, question, embedder) {
  const db = await getDepartmentDB(department);
  const queryVector = await embedder.embed(question);

  // Results are from this department's vectors only
  return db.search({ vector: queryVector, k: 5 });
}
```

